from queue import Queue

class employeeGraph:
    def __init__(self):
        self.reportee_manager = {}
        self.manager_reports = {}

    def insert(self, edges: list):
        self.reportee_manager = {}
        self.manager_reports = {}
        indegree = {}
        for a, b in edges:
            self.reportee_manager[b] = a
            indegree.setdefault(a, 0)
            indegree.setdefault(b, 0)
            indegree[a] += 1

        q = Queue()
        for i in indegree:
            if indegree[i] == 0:
                q.put(i)

        while q.qsize() > 0:
            i = q.get()
            if i in self.reportee_manager:
                manager = self.reportee_manager[i]
                self.manager_reports.setdefault(i, 0)
                self.manager_reports.setdefault(manager, 0)
                self.manager_reports[manager] += self.manager_reports[i] + 1
                indegree[manager] -= 1
                if indegree[manager] == 0:
                    q.put(manager)


    def put(self, edge):
        a, b = edge
        if b in self.reportee_manager and self.reportee_manager[b] == a:
            return
        self.reportee_manager[b] = a
        self.manager_reports.setdefault(b, 0)
        self.propagate(a, self.manager_reports[b] + 1)

    def update(self, edge):
        a, b = edge
        if b in self.reportee_manager and self.reportee_manager[b] == a:
            return
        if b in self.reportee_manager:
            self.manager_reports.setdefault(b, 0)
            self.propagate(self.reportee_manager[b], -1 * (self.manager_reports[b] + 1))

        self.reportee_manager[b] = a
        self.manager_reports.setdefault(b, 0)
        self.propagate(a, self.manager_reports[b] + 1)

    def propagate(self, employee, count):
        self.manager_reports.setdefault(employee, 0)
        self.manager_reports[employee] += count
        if employee in self.reportee_manager:
            self.propagate(self.reportee_manager[employee], count)

