import java.util.*;

class Employee {
    public String id;
    public int directAndIndirectReporteesCount;

    public Employee(String id) {
        this.id = id;
        this.directAndIndirectReporteesCount = 0;
    }
}

class EmployeeManagementSystem {
    public Map<String, String> managerMap;
    public Map<String, Employee> employeeIdMap;

    public EmployeeManagementSystem(List<List<String>> pairs) {
        managerMap = new HashMap<>();
        employeeIdMap = new HashMap<>();

        for (List<String> pair : pairs) {
            addEmployee(pair.get(0), pair.get(1));
        }
    }

    public void addEmployee(String managerId, String employeeId) {
        if (!employeeIdMap.containsKey(managerId)) {
            employeeIdMap.put(managerId, new Employee(managerId));
        }

        if (!employeeIdMap.containsKey(employeeId)) {
            employeeIdMap.put(employeeId, new Employee(employeeId));
        }

        int directAndIndirectReporteesCount = employeeIdMap.get(employeeId).directAndIndirectReporteesCount;

        managerMap.put(employeeId, managerId);

        String temp = employeeId;

        while (managerMap.containsKey(temp)) {
            temp = managerMap.get(temp);
            Employee emmployee = employeeIdMap.get(temp);
            emmployee.directAndIndirectReporteesCount = emmployee.directAndIndirectReporteesCount + 1 + directAndIndirectReporteesCount;
        }
    }

    public int findDirectAndIndirectReporteesCount(String employeeId) {
        return employeeIdMap.get(employeeId).directAndIndirectReporteesCount;
    }

    public void changeManager(String managerId, String employeeId) {
        int directAndIndirectReporteesCount = findDirectAndIndirectReporteesCount(employeeId);

        String temp = employeeId;

        while (managerMap.containsKey(temp)) {
            temp = managerMap.get(temp);
             Employee emmployee = employeeIdMap.get(temp);
            emmployee.directAndIndirectReporteesCount = emmployee.directAndIndirectReporteesCount - 1 - directAndIndirectReporteesCount;
        }

        managerMap.remove(employeeId);

        addEmployee(managerId, employeeId);
    }
}
public class Main
{
	public static void main(String[] args) {
		EmployeeManagementSystem employeeManagementSystem = new EmployeeManagementSystem(Arrays.asList(
                                                                    Arrays.asList("a", "b"),
                                                                    Arrays.asList("b", "c"),
                                                                    Arrays.asList("d", "f"),
                                                                    Arrays.asList("f", "g")
                                                                ));

        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("a"));    
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("b"));  
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("c"));  
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("d"));  
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("f"));  
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("g"));  

         employeeManagementSystem.changeManager("c", "d");

         System.out.println("*******");
         System.out.println("*******");


        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("a"));    
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("b"));  
        System.out.println(employeeManagementSystem.findDirectAndIndirectReporteesCount("c"));  
